# Import pymongo
import pymongo

def get_user(email):
    # Connect to local host
    client = pymongo.MongoClient("mongodb://localhost/")

    db = client["test"]
    coll = db["users"]
    # Find the user with email address passed in as a parameter
    user = coll.find({"email":email})

    # return the first document that matches
    return user[0]